/// Shared assertions for pipeline-generated module smoke tests.
///
/// Keeps each generated test file responsible only for constructing its module
/// while this helper owns the common public behavior contract expected from all
/// generated module classes.
void expectGeneratedModuleSmoke({
  required Object module,
  required String className,
  required String id,
  required String shader,
}) {
  test('$className instantiates', () {
    final m = module as dynamic;
    expect(m.id, id);
    expect(m.shader, shader);
  });

  test('$className presets are well-formed', () {
    final m = module as dynamic;
    expect(m.presets, isNotEmpty);
    for (final p in m.presets as Iterable<dynamic>) {
      expect(p.id, isNotEmpty);
      expect(p.name, isNotEmpty);
    }
  });

  test('$className metadata is consistent', () {
    final m = module as dynamic;
    expect(m.metadata.id, m.id);
  });
}

